import java.io.*;
import jakarta.servlet.*;
import jakarta.servlet.http.*;

public class LifecycleServlet extends HttpServlet {

 // Instance variable - shared across all requests (NOT thread-safe!)
 private int requestCount = 0;

 @Override
 public void init() throws ServletException {
 // Called ONCE when servlet is first loaded
 System.out.println("LifecycleServlet: init() called - Initializing resources");
 // Initialize database connections, load config, etc.
 }

 @Override
 protected void service(HttpServletRequest request, HttpServletResponse response) 
 throws ServletException, IOException {
 // Called for EVERY request - dispatches to doGet/doPost
 System.out.println("LifecycleServlet: service() called - Handling request #" + (++requestCount));
 super.service(request, response); // Dispatches to doGet(), doPost(), etc.
 }

 @Override
 protected void doGet(HttpServletRequest request, HttpServletResponse response) 
 throws ServletException, IOException {
 response.setContentType("text/html");
 PrintWriter out = response.getWriter();
 out.println("<html><body>");
 out.println("<h2>Request Count: " + requestCount + "</h2>");
 out.println("</body></html>");
 }

 @Override
 public void destroy() {
 // Called ONCE when servlet is unloaded
 System.out.println("LifecycleServlet: destroy() called - Cleaning up resources");
 // Close database connections, release file handles, etc.
 }
}

import java.io.*;
import java.util.concurrent.atomic.AtomicLong;
import jakarta.servlet.*;
import jakarta.servlet.http.*;

public class ThreadSafeCounterServlet extends HttpServlet {

 // AtomicLong is thread-safe - uses CAS operations
 private AtomicLong hitCounter = new AtomicLong(0);

 // Synchronized method alternative
 private long syncCounter = 0;

 @Override
 public void init() throws ServletException {
 System.out.println("Initializing ThreadSafeCounterServlet");
 }

 @Override
 protected void doGet(HttpServletRequest request, HttpServletResponse response) 
 throws ServletException, IOException {

 // Method 1: Using AtomicLong (preferred)
 long currentHits = hitCounter.incrementAndGet();

 // Method 2: Synchronized block (alternative)
 synchronized(this) {
 syncCounter++;
 }

 response.setContentType("text/html");
 PrintWriter out = response.getWriter();
 out.println("<html><body>");
 out.println("<h1>Page Hits: " + currentHits + "</h1>");
 out.println("</body></html>");
 }

 @Override
 public void destroy() {
 // Log final count or save to database
 System.out.println("Final hit count: " + hitCounter.get());
 }
}

import jakarta.servlet.*;
import jakarta.servlet.annotation.WebListener;
import java.sql.Connection;
import java.sql.DriverManager;
import java.sql.SQLException;

@WebListener
public class AppInitializationListener implements ServletContextListener {

 private Connection dbConnection;

 @Override
 public void contextInitialized(ServletContextEvent sce) {
 // Called when web application starts
 System.out.println("Web Application Starting - Initializing resources");

 try {
 // Initialize database connection pool
 Class.forName("com.mysql.cj.jdbc.Driver");
 dbConnection = DriverManager.getConnection(
 "jdbc:mysql://localhost:3306/mydb", "root", "password");

 // Store connection in ServletContext for access by all servlets
 ServletContext context = sce.getServletContext();
 context.setAttribute("dbConnection", dbConnection);

 System.out.println("Database connection established");
 } catch (ClassNotFoundException | SQLException e) {
 System.err.println("Failed to initialize: " + e.getMessage());
 }
 }

 @Override
 public void contextDestroyed(ServletContextEvent sce) {
 // Called when web application shuts down
 System.out.println("Web Application Shutting Down - Cleaning up");

 // Clean up database connection
 if (dbConnection != null) {
 try {
 dbConnection.close();
 System.out.println("Database connection closed");
 } catch (SQLException e) {
 System.err.println("Error closing connection: " + e.getMessage());
 }
 }
 }
}
